#include "rain_sensor.h"
#include <Arduino.h>
#define RAIN_A 34
#define RAIN_D 35
static int _raw=0;static bool _rain=false;
static unsigned long _last=0;
void rain_setup(){pinMode(RAIN_A,INPUT);pinMode(RAIN_D,INPUT);Serial.println("[rain] OK");}
void rain_loop(){if(millis()-_last<500)return;_last=millis();_raw=analogRead(RAIN_A);_rain=!digitalRead(RAIN_D);}
int rain_get_raw(){return _raw;}
bool rain_detected(){return _rain;}
